INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "リン", 0.0, 10040, 24, 102601, 24001, "2020/04/30 12:00:00", "あたしだって\nやるときはやるよ！", 0, 1, 1, 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "リン", 0.0, 10040, 24, 102601, 24002, "2020/04/30 12:00:00", "ふぅ…\nこれであたしの仕事は\n終わりだね", 1, 1, 1, 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "リン", 0.0, 10040, 24, 102601, 24003, "2020/04/30 12:00:00", "終わった終わった\n一人でもなんとか\nなるもんだね", 2, 1, 1, 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "リン", 0.0, 10040, 24, 102601, 24004, "2020/04/30 12:00:00", "やったね！\nこれでようやく\nサボれるよ…", 3, 2, 2, 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "リン", 0.0, 10040, 24, 102601, 24005, "2020/04/30 12:00:00", "チーズが欲しいなら\nきちんと働いて\n買いに来なよ", 4, 1, 1, 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "リン", 0.0, 10040, 24, 102601, 24006, "2020/04/30 12:00:00", "あたしを敵に回した\n恐ろしさ\n思い知ったか！", 5, 2, 2, 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "リン", 0.0, 10040, 24, 102601, 24007, "2020/04/30 12:00:00", "あたしも意外と\nやるもんでしょ？", 6, 2, 2, 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "リン", 0.0, 10040, 24, 102601, 24008, "2020/04/30 12:00:00", "疲れた…\nねずみの逃げ足\n速すぎるよ…", 7, 4, 4, 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "リン", 0.0, 10040, 24, 102601, 24009, "2020/04/30 12:00:00", "このままじゃ\nまっひ～に\n叱られちゃうよ", 8, 4, 4, 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "リン", 0.0, 10040, 24, 102601, 24010, "2020/04/30 12:00:00", "まじめに\nやったんだけどな…\n悔しいな～", 9, 4, 4, 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "リン", 0.0, 10040, 24, 102601, 24011, "2020/04/30 12:00:00", "やられた…\nねずみって意外と\nてごわいね", 10, 4, 4, 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "リン", 0.0, 10040, 24, 102601, 24012, "2020/04/30 12:00:00", "おのれ～\nあたしのチーズを\n盗みやがって～！", 11, 4, 4, 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "リン", 0.0, 10040, 24, 102601, 24013, "2020/04/30 12:00:00", "疲れた…\nけど、次こそは\n守り抜くよ…", 12, 4, 1, 1.81, "2030/12/17 14:59:59");
